#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-27

# cc-consolidate-milestones.sh — sweep per-version "CC X.Y.Z adoption"
# milestones into a single rolling "CC adoption" umbrella, then close the
# emptied per-version milestones.
#
# Idempotent self-heal: a steady state finds no stray milestones and exits 0
# with zero mutations. The first run migrates pre-existing per-version
# milestones; later runs are no-ops. Safe to wire into the cron tick.
#
# Why: cc-release-watch.mjs used to name the filer milestone "CC X.Y.Z
# adoption" — one per upstream version — producing 8+ near-empty milestones.
# It now targets the single "CC adoption" umbrella; this script migrates the
# pre-existing per-version milestones and self-heals any that reappear.
# Per-version traceability is untouched — it lives in the `Key: <slug>+<version>`
# issue body marker (cc-file-adoption-issues.sh) and shared/cc-snapshots/<version>.md,
# both version-keyed and independent of the milestone.
#
# Graduation escape hatch: to KEEP a cluster as a human bundle, rename its
# milestone out of SWEEP_REGEX (e.g. "M146 — CC 2.1.143 hardening"); this
# script then leaves it alone.
#
# Inputs (env):
#   GH_REPO         "owner/repo" — required (workflow injects ${{ github.repository }})
#   UMBRELLA_TITLE  umbrella milestone title (default "CC adoption")
#   SWEEP_REGEX     awk ERE for per-version titles to sweep
#                   (default '^CC 2\.1\.[0-9]+ adoption$')
#   DRY_RUN         "1" → print actions, mutate nothing (default "0")
#   SLEEP_BETWEEN   seconds between write calls (default 1; dodges gh
#                   secondary rate-limit on bursts)
#
# Side effects (via gh, skipped when DRY_RUN=1):
#   - Creates UMBRELLA_TITLE if missing
#   - Reassigns each stray milestone's OPEN issues to the umbrella
#   - Closes a stray milestone once it has zero open issues
#
# Exit 0 on success (including no-op). Hard-fails on missing GH_REPO or gh
# errors — empty result sets are exit 0 (not errors), so no error-masking guards.

set -euo pipefail

GH_REPO="${GH_REPO:?GH_REPO is required (owner/repo)}"
UMBRELLA_TITLE="${UMBRELLA_TITLE:-CC adoption}"
SWEEP_REGEX="${SWEEP_REGEX:-^CC 2\.1\.[0-9]+ adoption$}"
DRY_RUN="${DRY_RUN:-0}"
SLEEP_BETWEEN="${SLEEP_BETWEEN:-1}"

note() { echo "[consolidate] $*"; }
maybe_sleep() { [ "$DRY_RUN" = "1" ] || sleep "$SLEEP_BETWEEN"; }

# Resolve umbrella milestone number (create if missing). A missing title makes
# jq emit nothing and gh exit 0 — that's the create path, not an error.
resolve_umbrella() {
  local n
  n=$(gh api "repos/${GH_REPO}/milestones?state=open&per_page=100" --paginate \
        --jq ".[] | select(.title==\"${UMBRELLA_TITLE}\") | .number")
  if [ -n "$n" ]; then
    echo "$n"
    return
  fi
  if [ "$DRY_RUN" = "1" ]; then
    note "DRY_RUN: would create umbrella milestone \"${UMBRELLA_TITLE}\""
    echo "0" # placeholder so dry-run can proceed
    return
  fi
  n=$(gh api -X POST "repos/${GH_REPO}/milestones" -f title="${UMBRELLA_TITLE}" --jq .number)
  note "created umbrella milestone \"${UMBRELLA_TITLE}\" (#$n)"
  echo "$n"
}

UMBRELLA_NUM=$(resolve_umbrella)
note "umbrella \"${UMBRELLA_TITLE}\" = #${UMBRELLA_NUM}"

# List open milestones, filter to stray per-version ones in awk (avoids
# jq regex-escaping pitfalls with the backslashes in SWEEP_REGEX). An empty
# list is a valid steady state, not an error.
STRAYS=$(gh api "repos/${GH_REPO}/milestones?state=open&per_page=100" --paginate \
  --jq '.[] | "\(.number)\t\(.title)"' \
  | awk -F'\t' -v u="$UMBRELLA_TITLE" -v re="$SWEEP_REGEX" '$2 ~ re && $2 != u {print}')

if [ -z "$STRAYS" ]; then
  note "no stray per-version milestones — nothing to do."
  exit 0
fi

swept=0
moved=0
closed=0
while IFS=$'\t' read -r M_NUM M_TITLE; do
  [ -z "${M_NUM:-}" ] && continue
  note "sweeping #${M_NUM} \"${M_TITLE}\""
  ISSUES=$(gh issue list --repo "${GH_REPO}" --milestone "${M_TITLE}" \
    --state open --limit 200 --json number --jq '.[].number')
  for iss in $ISSUES; do
    if [ "$DRY_RUN" = "1" ]; then
      note "  DRY_RUN: would move #${iss} → \"${UMBRELLA_TITLE}\""
    else
      gh api -X PATCH "repos/${GH_REPO}/issues/${iss}" -F milestone="${UMBRELLA_NUM}" >/dev/null
      note "  moved #${iss} → \"${UMBRELLA_TITLE}\""
      maybe_sleep
    fi
    moved=$((moved + 1))
  done
  # Close only once the milestone is actually empty (re-query, don't assume).
  if [ "$DRY_RUN" = "1" ]; then
    note "  DRY_RUN: would close #${M_NUM} once emptied"
    closed=$((closed + 1))
  else
    REMAIN=$(gh api "repos/${GH_REPO}/milestones/${M_NUM}" --jq '.open_issues')
    if [ "$REMAIN" = "0" ]; then
      gh api -X PATCH "repos/${GH_REPO}/milestones/${M_NUM}" -f state=closed >/dev/null
      note "  closed emptied #${M_NUM} \"${M_TITLE}\""
      closed=$((closed + 1))
      maybe_sleep
    else
      note "  #${M_NUM} still has ${REMAIN} open issue(s) — left open"
    fi
  fi
  swept=$((swept + 1))
done <<<"$STRAYS"

note "done: swept=${swept} milestone(s), moved=${moved} issue(s), closed=${closed}."
